code = """import pandas as pd, json
cases = pd.DataFrame(var_call_sYX5No73G0aKhF4eI05BSj64)
accounts = pd.DataFrame(var_call_nYE9eb8qYek9McsvVkZZ7Pna)
cases['account_clean'] = cases['accountid'].str.replace('#','', regex=False)
accounts['account_clean'] = accounts['clean_id']
# time window: past 6 quarters from 2022-10-26 -> starting 2021-07-01; filter by createddate between 2021-07-01 and 2022-10-26
cases['createddate'] = pd.to_datetime(cases['createddate'])
cases['closeddate'] = pd.to_datetime(cases['closeddate'])
cases = cases[(cases['createddate'] >= '2021-07-01') & (cases['createddate'] <= '2022-10-26')]
# compute closure time in hours
cases['closure_hours'] = (cases['closeddate'] - cases['createddate']).dt.total_seconds() / 3600.0
# join to states
merged = pd.merge(cases, accounts[['account_clean','ShippingState']], on='account_clean', how='left')
# drop missing states
merged = merged.dropna(subset=['ShippingState'])
# aggregate average closure time by state
state_stats = merged.groupby('ShippingState')['closure_hours'].mean().reset_index()
# pick state with minimum average closure time
best = state_stats.sort_values('closure_hours').head(1)
result = best['ShippingState'].iloc[0]
import json
result_json = json.dumps(result)
print('__RESULT__:')
print(result_json)"""

